/**
 * THE single source of the Web Bluetooth §7 page-realm UUID machinery for every
 * TypeScript bundle: the npm core, the extension-injected surface
 * (`src/beacio/api/*`) and the standalone CDN polyfill (`src/cdn/beacio.ts`)
 * all import the three GATT assigned-numbers tables and the §7.1 resolver
 * (`canonicalUUID` + `resolveUUIDName`) FROM HERE. Because each shipped artifact
 * is webpack/tsup-bundled, this source module is inlined into each build, so
 * every artifact stays dependency-free while the tables + resolver exist ONCE.
 *
 * The three `registries:begin/end` table blocks are GENERATED by
 * `scripts/registries/generate.mjs` from the vendored WebBluetoothCG registry
 * files in `registries/` — the same single source of truth as
 * `Shared (Extension)/UUIDResolver.swift` (Swift cannot import TS, so it stays
 * a separate generated target). Regenerate with:
 *   node scripts/registries/generate.mjs
 *
 * The resolver semantics are the STRICT §7.1 form (spec: "A valid UUID is a
 * lower-case 128-bit string"): a string argument must be a valid lowercase
 * 128-bit UUID or a registered name (looked up case-folded because the tables
 * key the registry's mixed-case published spellings — e.g.
 * `magnetic_flux_density_2D` — in lowercase). The bare 4/8-hex and uppercase
 * leniency of the wire helpers (`src/beacio/api/uuid-normalization.ts`) is
 * intentionally NOT offered here.
 *
 * ARCHITECTURE BOUNDARY: This file holds ONLY the three GATT assigned-numbers
 * tables (services/characteristics/descriptors) + the Web Bluetooth §7.1
 * resolver functions (canonicalUUID, resolveUUIDName, hexToUUID). No other
 * logic. No new exports. Every consumer bundles this inline, so accumulation
 * here is paid N times across consumers.
 */

/** §7 base UUID suffix; a 16/32-bit alias replaces the top 32 bits. */
export const BLUETOOTH_BASE_UUID_SUFFIX = "-0000-1000-8000-00805f9b34fb";

/** §7 "A valid UUID is a string that matches [this] regexp" (lowercase only). */
export const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/;

