/** Expand a validated 16/32-bit alias into the canonical lowercase 128-bit UUID. */
function hexToUUID(hex: number): string {
  return hex.toString(16).padStart(8, "0") + BLUETOOTH_BASE_UUID_SUFFIX;
}

/**
 * `BluetoothUUID.canonicalUUID(alias)` (§7): expand a 16/32-bit alias into the
 * canonical lowercase 128-bit UUID string. Applies the WebIDL `[EnforceRange]
 * unsigned long` conversion: ToNumber, reject non-finite, truncate toward zero,
 * reject outside [0, 2^32 − 1]. Fractional/numeric-string inputs CONVERT.
 */
export function canonicalUUID(alias: number): string {
  const converted = Number(alias);
  if (!Number.isFinite(converted)) {
    throw new TypeError(
      `Failed to execute 'canonicalUUID' on 'BluetoothUUID': ` +
        `Value is not a valid unsigned long: ${alias}`,
    );
  }
  const truncated = Math.trunc(converted);
  if (truncated < 0 || truncated > 0xffffffff) {
    throw new TypeError(
      `Failed to execute 'canonicalUUID' on 'BluetoothUUID': ` +
        `Value is not a valid unsigned long: ${alias}`,
    );
  }
  // `+ 0` normalizes -0 (from truncating e.g. -0.5) to 0.
  return hexToUUID(truncated + 0);
}

/**
 * §7.1 ResolveUUIDName, scoped to a single GATT assigned-numbers table.
 * Names are table-scoped because the registries reuse names across categories
 * (`current_time` is service 0x1805 AND characteristic 0x2A2B), so
 * `getService` / `getCharacteristic` / `getDescriptor` each consult only their
 * own table.
 *
 *  1. unsigned long           → canonicalUUID(name)
 *  2. valid lowercase UUID    → pass through
 *  3. registered name         → canonicalUUID(alias) (case-folded lookup)
 *  4. otherwise               → throw a TypeError
 *
 * `String(name)` coerces page-realm non-string garbage so it stringifies (and
 * misses) rather than dying on `.toLowerCase`.
 */
export function resolveUUIDName(
  name: string | number,
  table: Record<string, number>,
  getter: string,
): string {
  if (typeof name === "number") return canonicalUUID(name);
  const value = String(name);
  if (UUID_RE.test(value)) return value;
  const alias = table[value.toLowerCase()];
  if (alias !== undefined) return hexToUUID(alias);
  throw new TypeError(
    `Failed to execute '${getter}' on 'BluetoothUUID': Invalid UUID or registry name: "${value}"`,
  );
}
